import { scv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const colorSwatchVariants = scv({
  slots: {
    root: [
      'relative isolate inline-flex shrink-0 overflow-hidden border border-input bg-background shadow-sm',
      'data-[no-color]:bg-muted/40'
    ],
    checker: `absolute inset-0 bg-[linear-gradient(45deg,rgba(0,0,0,0.08)_25%,transparent_25%,transparent_75%,rgba(0,0,0,0.08)_75%),linear-gradient(45deg,rgba(0,0,0,0.08)_25%,transparent_25%,transparent_75%,rgba(0,0,0,0.08)_75%)] bg-[length:8px_8px] bg-[position:0_0,4px_4px]`,
    fill: 'absolute inset-0 bg-[var(--soybean-color-swatch-color)]'
  },
  variants: {
    size: {
      xs: {
        root: 'size-5 text-2xs'
      },
      sm: {
        root: 'size-5.5 text-xs'
      },
      md: {
        root: 'size-6 text-sm'
      },
      lg: {
        root: 'size-6.5 text-base'
      },
      xl: {
        root: 'size-7 text-lg'
      },
      '2xl': {
        root: 'size-8 text-xl'
      }
    },
    shape: {
      square: {
        root: 'rounded-md'
      },
      circle: {
        root: 'rounded-full'
      }
    }
  },
  defaultVariants: {
    size: 'md',
    shape: 'square'
  }
});

type ColorSwatchVariants = VariantProps<typeof colorSwatchVariants>;

export type ColorSwatchShape = NonNullable<ColorSwatchVariants['shape']>;

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
